import { useEffect, useRef, useState } from "react";
import { clamp, ease } from "./helpers";

const TIMELINE = [
  {
    year: "1999",
    desc: "The first online shopping platform gained traction.",
    title: "Medium",
    sub: "Courier services",
  },
  {
    year: "2015",
    desc: "A social media platform introduced shoppable tags, where people could directly sell on the platform.",
    title: "Medium",
    sub: "Fleet operators",
  },
  {
    year: "2017",
    desc: "E-commerce platforms offered same-day delivery services to compete on speed and reach. Premium members.",
    title: "Medium",
    sub: "Fleet operators + delivery drivers",
  },
  {
    year: "2019",
    desc: "Food delivery platforms competed for speed promising delivery in 10–15 minutes from micro-fulfillment centers.",
    title: "Medium",
    sub: "Delivery Partners + Dark stores",
  },
  {
    year: "2021",
    desc: "Quick commerce gained popularity for providing sub-15 minute delivery for premium products.",
    title: "Medium",
    sub: "Delivery Partners + Dark stores",
  },
  {
    year: "2025",
    desc: "On-demand services (cleaning, cooking, etc) can be booked instantly.",
    title: "Medium",
    sub: "For everything instantly",
  },
];

function TimelineCard({ item, slideIn }) {
  return (
    <div style={{
      minWidth: 220, maxWidth: 240, flexShrink: 0,
      background: "white",
      borderRadius: 16,
      overflow: "hidden",
      boxShadow: "0 6px 32px rgba(0,0,0,0.20), 0 1px 4px rgba(0,0,0,0.10)",
      opacity: slideIn,
      transform: `translateX(${(1 - slideIn) * 100}px)`,
      willChange: "transform, opacity",
    }}>
      {/* Top section with year */}
      <div style={{ padding: "18px 18px 14px" }}>
        <div style={{
          display: "inline-block",
          background: "#e53e3e", color: "white",
          fontSize: 16, fontWeight: 800,
          padding: "4px 14px", borderRadius: 999,
          marginBottom: 12,
          fontFamily: "'Inter',sans-serif",
        }}>{item.year}</div>
        <p style={{
          fontSize: 13, color: "#444", lineHeight: 1.6,
          fontFamily: "'Inter',sans-serif",
        }}>{item.desc}</p>
      </div>

      {/* Divider */}
      <div style={{ height: 1, background: "#f0f0f0" }} />

      {/* Medium + sub label */}
      <div style={{ padding: "12px 18px 14px" }}>
        <p style={{
          fontSize: 14, fontWeight: 800, color: "#1a1a1a",
          fontFamily: "'Inter',sans-serif", letterSpacing: 0.3,
          textTransform: "uppercase", marginBottom: 3,
        }}>{item.title}</p>
        <p style={{
          fontSize: 12, color: "#888",
          fontFamily: "'Inter',sans-serif", lineHeight: 1.5,
        }}>{item.sub}</p>
      </div>

      {/* BW illustration */}
      <div style={{
        height: 120, margin: "0 14px 14px",
        background: "linear-gradient(145deg,#d0cdc8,#b5b2ad)",
        borderRadius: 10, position: "relative", overflow: "hidden",
        display: "flex", alignItems: "center", justifyContent: "center",
      }}>
        {/* Depth shading */}
        <div style={{
          position: "absolute", inset: 0,
          background: "linear-gradient(135deg,transparent 40%,rgba(0,0,0,0.25) 100%)",
        }} />
        {/* Truck silhouette */}
        <div style={{
          width: 70, height: 36, background: "rgba(45,45,45,0.65)",
          borderRadius: 5, position: "relative", zIndex: 2,
        }}>
          <div style={{
            position: "absolute", right: 0, top: 0,
            width: 24, height: 24,
            background: "rgba(35,35,35,0.7)", borderRadius: "5px 5px 0 0",
          }} />
        </div>
        {/* Road line */}
        <div style={{
          position: "absolute", bottom: 12, left: 14, right: 14,
          height: 5, background: "rgba(30,30,30,0.35)", borderRadius: 3,
        }} />
        {/* Red dot */}
        <div style={{
          position: "absolute", top: 8, right: 8,
          width: 10, height: 10, borderRadius: "50%", background: "#e53e3e", zIndex: 5,
        }} />
      </div>
    </div>
  );
}

export default function WorkforceSection() {
  const sectionRef = useRef(null);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;
      const scrolled = -el.getBoundingClientRect().top;
      const total = el.offsetHeight - window.innerHeight;
      setProgress(Math.max(0, Math.min(1, scrolled / (total * 0.92))));
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // Header text fades in first
  const headerT = ease(clamp(progress / 0.15, 0, 1));

  // Each card slides in at evenly spaced intervals after 10% scroll
  const cardProgress = (i) => {
    const start = 0.10 + i * 0.13;
    const end = start + 0.14;
    return ease(clamp((progress - start) / (end - start), 0, 1));
  };

  return (
    /* 350vh — plenty of room to stagger 6 cards */
    <div ref={sectionRef} style={{ height: "350vh", position: "relative" }}>
      <div style={{
        position: "sticky", top: 0, height: "100vh",
        overflow: "hidden",
        display: "flex", flexDirection: "column",
        background: "#fff",
      }}>
        {/* ── Full-width header (white) ── */}
        <div style={{
          padding: "80px 8vw 40px",
          textAlign: "center",
          opacity: headerT,
          transform: `translateY(${(1 - headerT) * 30}px)`,
        }}>
          <h2 style={{
            fontFamily: "'Playfair Display','Georgia',serif",
            fontSize: "clamp(42px,7vw,100px)",
            fontWeight: 900, color: "#e53e3e",
            lineHeight: 1.05, margin: 0,
          }}>
            The Workforce<br />Behind Every Order
          </h2>
          <p style={{
            fontSize: "clamp(14px,1.15vw,18px)", color: "#444",
            lineHeight: 1.75, maxWidth: 780,
            margin: "20px auto 8px",
          }}>
            India's doorstep economy operates at the intersection of logistics,
            technology, and human workforce. But that wasn't the case 15 years ago.
            Let's look at how the gig economy evolved with various business models
            over the last 3 decades.
          </p>
          <p style={{ fontSize: 13, color: "#aaa", fontStyle: "italic" }}>
            Sources:{" "}
            <span style={{ textDecoration: "underline", cursor: "pointer" }}>Kearney</span>{" "}
            <span style={{ textDecoration: "underline", cursor: "pointer" }}>Young Urban Project</span>{" "}
            <span style={{ textDecoration: "underline", cursor: "pointer" }}>Shiproket</span>
          </p>
        </div>

        {/* ── Cards row — dark background panel ── */}
        <div style={{
          flex: 1,
          background: "#111",
          display: "flex",
          alignItems: "center",
          padding: "0 6vw",
          overflow: "hidden",
          gap: 20,
        }}>
          {TIMELINE.map((item, i) => (
            <TimelineCard key={item.year} item={item} slideIn={cardProgress(i)} />
          ))}
        </div>
      </div>
    </div>
  );
}
